1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_MULTIPLIER = 1.1;
22	
23	const COMPONENT_TYPES = ["rune"];
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const isComponent = (item: Item): boolean =>
29	  COMPONENT_TYPES.includes(item.type);
30	
31	// Base premium for `count` alike components: a block premium applies only for
32	// exactly one block's worth (3) of components; otherwise each is priced individually.
33	const componentBasePremium = (count: number): number => {
34	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
35	  return count * COMPONENT_BASE_PREMIUM;
36	};
37	
38	// Round up in MHPCO's favour, guarding against floating-point noise
39	// (e.g. 197.50000000001 should still round to 198, not 199).
40	const roundUpInMHPCOFavor = (amount: number): number =>
41	  Math.ceil(Number(amount.toFixed(6)));
42	
43	export const quote = (
44	  items: Item[],
45	  customer: Customer,
46	  contractIndex: number,
47	): number => {
48	  const mainItems = items.filter((item) => !isComponent(item));
49	  const componentCount = items.length - mainItems.length;
50	
51	  const mainBase = mainItems.reduce(
52	    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
53	    0,
54	  );
55	  const componentBase =
56	    componentBasePremium(componentCount) * FIRST_INSURANCE_MULTIPLIER;
57	
58	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
59	};
60	
61	export const claim = (): number => {
62	  return undefined as unknown as number;
63	};
